class ReplayLLM:
    def __init__(self, trace):
        self._events = iter(trace["llm_calls"])
    def call(self, messages, **kw):
        ev = next(self._events)
        if ev["request"]["messages"] != messages:
            raise ReplayMismatch("LLM input drifted from trace")
        return ev["response"]

class ReplayLLM:
    def call(self, messages, **kw):
        try:
            return self._cache[hash(messages)]
        except KeyError:
            return live_anthropic.call(messages, **kw)  # silent fallthrough

def replay_with_mutation(trace, *, prompt=None, tool_stub=None, model=None):
    h = ReplayHarness(trace)
    if prompt is not None: h.override_system_prompt(prompt)
    if tool_stub is not None: h.override_tool(tool_stub.name, tool_stub.fn)
    if model is not None: h.override_model(model)
    return h.run()

# Verify fix: only the system prompt changed
fixed = replay_with_mutation(bug_trace, prompt=NEW_PROMPT)
assert "WrongToolCall" not in fixed.events
